  ('social-worker-moex-02269', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '因應經濟的全球化，不同體制的福利國家採取的策略重點有所不同，請問下列敘述何者正確？', '["自由主義的福利國家偏重消極的勞動市場方案，增加失業給付等政府社會支出", "保守主義模式的福利國家偏向勞動市場的彈性化，減少政府的社會支出", "社會民主模式的福利國家偏重積極的勞動市場方案，例如就業服務和職業訓練等社會支出", "自由主義模式的福利國家認為需求導向的經濟需要更增加政府的社會支出，以維持社會消費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02270', 'social-worker', 'social-worker-moex-106-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '學者T. H. Marshall 認為公民權利（citizenship）包含三個部分，下列何者不包括在內？', '["政治權（political right）", "文化權（cultural right）", "公民權（civil right）", "社會權（social right）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "89b4d02ec516", "answer_pdf_sha1": "12ce7bac1046", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02271', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'essay', '依照兒童及少年福利與權利保障法第 62 條提及，兒童及少年因家庭發生重大變故
導致無法正常生活於其家庭者，相關人員及單位得為其申請安置及輔助，而寄養家
庭服務即是其中之一。然近年來常聽聞兒童及少年因原生家庭的功能未能恢復，使
兒童及少年長年留置或遊走在不同的寄養家庭之間，造成對兒童及少年生理及心理
不同層面的影響，請用Erik Erikson之心理發展理論說明其運用在寄養家庭服務可
能帶來的問題和影響為何？（10 分）社會工作者又要如何去提出有效的解決之道
及處遇方法。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02272', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'essay', '依據行政院主計總處的失業率公布，45歲到64歲的中高齡失業人口比率歷年來約占
2%到3%之間。相對於失業人口雖非最高，但從其對個人家庭甚至社會而言，將會造
成不同層面的影響。著名的成人發展理論學者Daniel Levinson曾提出成年發展的八個
階段，並提到對中年人而言，職場變動將會造成成年中期的不同問題，請說明：
D. Levinson的成年發展八階段為何？（10分）
對於中高齡失業所造成的各種影響，社會工作者要如何因應並提出解決的方法。
（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02273', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '過往常以電腦資訊處理的概念來比喻腦部功能，近年則以多單位連結與平行分工處理的概念 （parallel-distributed processing, PDP模式）來形容。以PDP模式來形容腦部的思考與認知處理，下列何者 正確？ 資料程式集中在腦部的某個部分 記憶能被直接儲存 學習是透過經驗組成單位間連結線索與強度逐漸累積產生 腦部無法同時處理認知和記憶', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02274', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關佛洛伊德（Sigmund Freud）理論觀點的敘述，下列何者錯誤？ 理論觀點影響深遠，但缺乏實證研究的印證，部分受到心理學家質疑與修正 人類行為主要是受到防衛機制（defense mechanism）所驅使，防衛機制的作用力及對其抑制都會影響人 類行為 人格架構由本我（id）、自我（ego）、超我（superego）所組成 心理動力理論認為人格的發展會經過不同的性心理階段（psychosexual stages）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02275', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '研究發現，成年人進入中年期時，變得更具有傳承的使命感。McAdams及Aubin等人所提出的傳承模型， 下列何者不是該模型的七個元素？ 內心渴望長存，希望被他人需要  孤立於家庭生活之外 關懷下一代的出路與生涯發展  創造、維護或貢獻個人所有', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02276', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '班度拉（Albert Bandura）將人類視為有意識、主動思考的生物，可與環境產生互動。因此，若就社會學 習理論觀之，下列敘述何者錯誤？ 人們必須透過直接的學習，才能夠達到真正學習的效果 強調自我效能（self-efficacy）對目標達成的影響，當人們相信自己有能力達成目標時，達成預期目標 的可能性較大 學習可以透過觀察他人而獲得知識，不必依賴直接參與的經驗 倘若讓兒童觀看暴力攻擊的影片，其攻擊行為會比觀看普通影片的兒童更多', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02277', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '布里默（Brim）（1975）和布朗芬布倫納（Bronfenbrenner）（1977）將社會中的系統分成四個範疇或系 統層次，下列對各系統之敘述何者錯誤？ 微視系統（microsystem）是指參與者直接接觸的系統，家庭、學校、工作場所等都屬於這類系統 中間系統（mesosystem）是指個人生活的環境網絡，每個案主都生活在自己的中間系統之中 外部系統（exosystem）是指影響個人系統的較大的機構，個人有很多機會直接參與或介入的機構，對 生活有著深遠的影響 鉅視系統（macrosystem）對個體的社會活動有很大的影響力，如文化、歷史事件等', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02278', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對柯爾柏格（Kohlberg）道德發展理論的評論，何者錯誤？ 這個理論比較強調人們的實際做法，而非想法 7歲的兒童受限於口語表達能力，其實他們不僅會思考行為，也會思考行為背後的動機 這個理論具有文化偏誤，不同文化或生活情境的人的道德發展是有差異的 是一個立基於男性觀點的理論，女性對道德兩難困境的看法與男性不同', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02279', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Kohlberg和Gilligan是道德發展理論的兩位重要學者，他們的理論核心分別為何？ 認知vs.關係    法理vs.情感 正義vs.關懷    問題解決vs.關係建立', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02280', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Levison的成年發展理論的敘述，下列何者正確？ 該理論認為成年期沒有階段的區別 該理論認為成年期的生活均在穩定中發展，不會有太大的改變 該理論認為成年期是在愛情、職業、友誼、價值觀及生活型態的選擇階段 該理論認為成年人的生活架構是在兒童期即已建立完成', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02281', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於生命歷程觀點的敘述，何者正確？ 認為「世代」是指不同年齡層在不同時空背景下，具有共同興趣的一群人 「過渡期」是指人在一生中扮演和轉換不同的角色與身分的時期 「轉捩點」是指人在人生旅途中，沒有改變的階段 認為人無法有自由意志來選擇自己的生命歷程建構', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02282', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '月華32歲結婚後生下一女，女兒申請到美國大學獎學金後就離家求學，目前已經在美國定居。月華發現 自己這幾年來，愈來愈難面對只有她與丈夫的二人生活，她向社會工作師表達自己對生活的不滿意，現 年55歲的月華想要離婚但又難以決定。社會工作師若就家庭生命週期觀點評估，月華可能是處於家庭生 命週期那個階段？ 有新家庭成員的家庭  有青少年的家庭  子女離巢的家庭  生命晚期的家庭', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02283', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '貧窮是對婦女產前與產後新生兒發展影響相當大的社會危險因素。貧窮可能帶給懷孕婦女或新生兒何種 風險？ 父母可能有先天性的家族疾病    讓父母因而無法關懷孩子 新生兒出生率高    影響父母提供孩子應有的養育環境能力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02284', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於服務未成年青少女懷孕的社工人員可能提供服務的敘述，何者是社工人員一定要做的事？ 協助向使其受孕的對象爭取調解金     協助由正在就讀的學校辦理退學 協助其完成結婚登記    協助穩定青少女在孕期間的生心理狀況', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02285', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '嬰幼兒與主要照顧者的依附關係是否能建立，對嬰幼兒未來性格的發展有相當重要的影響。下列那一個 是造成嬰幼兒與主要照顧者依附失敗的可能原因？ 嬰幼兒的外貌符合正常嬰幼兒的可愛特質    主要照顧者常表現出憂鬱和壓力的樣子 主要照顧者的伴侶能予以支持  主要照顧者沒有環境壓力，能專心照顧嬰幼兒', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "200b3b0862fc", "answer_pdf_sha1": "9fe76495339a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
